public class Solution {
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        if (n == 0) return 0;
        Arrays.sort(nums);
        long maxLen = 1;
        for (int left = 0; left < n; left++) {
            long target = nums[left] * k;
            int low = left;
            int high = n - 1;
            int right = left - 1;
            while (low <= high) {
