import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        if (n == 0) return 0; // but according to constraints, n is >=1
        Arrays.sort(nums);
        long max_len = 1;
        for (int i = 0; i < n; i++) {
            long target = k * nums[i];
            int low = i;
            int high = n - 1;
            int best_j = i - 1;
            while (low <= high) {
                int mid = (low + high) / 2;
                if (nums[mid] <= target) {
                    best_j = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            if (best_j >= i) {
                int len = best_j - i + 1;
                if (len > max_len) {
                    max_len = len;
                }
            }
        }
        return n - max_len;
    }
}

